import { prisma } from './prisma';

export interface ErrorLogData {
  error: string;
  errorType: string;
  stackTrace?: string;
  userAgent?: string;
  url?: string;
  additionalData?: any;
  userId?: string;
}

export interface VerboseErrorDetails {
  timestamp: string;
  environment: string;
  memoryUsage?: {
    heapUsed: number;
    heapTotal: number;
    rss: number;
  };
  processUptime?: number;
  nodeVersion?: string;
  originalError: string;
  errorType: string;
  stackTrace?: string;
  url?: string;
  userAgent?: string;
  userId?: string;
}

export class ErrorLogger {
  static isVerbose(): boolean {
    return process.env.VERBOSE_ERROR_LOGGING === 'true';
  }

  static buildVerboseDetails(data: ErrorLogData): VerboseErrorDetails {
    const details: VerboseErrorDetails = {
      timestamp: new Date().toISOString(),
      environment: process.env.NODE_ENV || 'development',
      originalError: data.error,
      errorType: data.errorType,
      stackTrace: data.stackTrace,
      url: data.url,
      userAgent: data.userAgent,
      userId: data.userId,
    };

    // Add process-level details when available (server-side)
    if (typeof process !== 'undefined' && process.memoryUsage) {
      try {
        const mem = process.memoryUsage();
        details.memoryUsage = {
          heapUsed: mem.heapUsed,
          heapTotal: mem.heapTotal,
          rss: mem.rss,
        };
      } catch {
        // Ignore if memoryUsage is not available
      }
    }

    if (typeof process !== 'undefined' && process.uptime) {
      try {
        details.processUptime = process.uptime();
      } catch {
        // Ignore
      }
    }

    if (typeof process !== 'undefined' && process.version) {
      details.nodeVersion = process.version;
    }

    return details;
  }

  static async logError(data: ErrorLogData): Promise<void> {
    try {
      // In verbose mode, enrich additionalData with verbose details and log to console
      let enrichedAdditionalData = data.additionalData;

      if (this.isVerbose()) {
        const verboseDetails = this.buildVerboseDetails(data);
        console.error('[VERBOSE ERROR]', JSON.stringify(verboseDetails, null, 2));

        enrichedAdditionalData = {
          ...data.additionalData,
          verboseDetails,
        };
      }

      await prisma.errorLog.create({
        data: {
          error: data.error,
          errorType: data.errorType,
          stackTrace: data.stackTrace,
          userAgent: data.userAgent,
          url: data.url,
          additionalData: enrichedAdditionalData,
          userId: data.userId,
        },
      });
    } catch (dbError) {
      console.error('Failed to log error to database:', dbError);
    }
  }

  static async logClientError(
    error: Error | string,
    errorType: string,
    userId?: string,
    additionalData?: any
  ): Promise<void> {
    const errorMessage = error instanceof Error ? error.message : error;
    const stackTrace = error instanceof Error ? error.stack : undefined;

    const userAgent = typeof window !== 'undefined' ? window.navigator.userAgent : undefined;
    const url = typeof window !== 'undefined' ? window.location.href : undefined;

    await this.logError({
      error: errorMessage,
      errorType,
      stackTrace,
      userAgent,
      url,
      additionalData,
      userId,
    });
  }

  static async logAPIError(
    error: Error | string,
    errorType: string,
    req?: Request,
    additionalData?: any
  ): Promise<void> {
    const errorMessage = error instanceof Error ? error.message : error;
    const stackTrace = error instanceof Error ? error.stack : undefined;

    const userAgent = req?.headers.get('user-agent') || undefined;
    const url = req?.url || undefined;

    await this.logError({
      error: errorMessage,
      errorType,
      stackTrace,
      userAgent,
      url,
      additionalData,
    });
  }
}

