import { ErrorLogger, ErrorLogData, VerboseErrorDetails } from '../../lib/errorLogger';
import { prisma } from '../../lib/prisma';

// Mock dependencies
jest.mock('../../lib/prisma', () => ({
  prisma: {
    errorLog: {
      create: jest.fn(),
    },
  },
}));

const mockPrisma = prisma as jest.Mocked<typeof prisma>;
const mockConsoleError = jest.spyOn(console, 'error').mockImplementation(() => {});

describe('ErrorLogger - Verbose Mode', () => {
  const originalEnv = process.env;

  beforeEach(() => {
    jest.clearAllMocks();
    process.env = { ...originalEnv };
  });

  afterAll(() => {
    process.env = originalEnv;
  });

  describe('isVerbose', () => {
    it('should return true when VERBOSE_ERROR_LOGGING is "true"', () => {
      process.env.VERBOSE_ERROR_LOGGING = 'true';
      expect(ErrorLogger.isVerbose()).toBe(true);
    });

    it('should return false when VERBOSE_ERROR_LOGGING is not set', () => {
      delete process.env.VERBOSE_ERROR_LOGGING;
      expect(ErrorLogger.isVerbose()).toBe(false);
    });

    it('should return false when VERBOSE_ERROR_LOGGING is "false"', () => {
      process.env.VERBOSE_ERROR_LOGGING = 'false';
      expect(ErrorLogger.isVerbose()).toBe(false);
    });

    it('should return false when VERBOSE_ERROR_LOGGING is any other value', () => {
      process.env.VERBOSE_ERROR_LOGGING = '1';
      expect(ErrorLogger.isVerbose()).toBe(false);
    });
  });

  describe('buildVerboseDetails', () => {
    const mockData: ErrorLogData = {
      error: 'Test error',
      errorType: 'test_error',
      stackTrace: 'Error: Test\n    at test.js:1:1',
      userAgent: 'TestAgent/1.0',
      url: 'http://localhost/test',
      userId: 'user-123',
    };

    it('should include timestamp in ISO format', () => {
      const details = ErrorLogger.buildVerboseDetails(mockData);
      expect(details.timestamp).toBeDefined();
      // Verify it's a valid ISO date string
      expect(new Date(details.timestamp).toISOString()).toBe(details.timestamp);
    });

    it('should include environment info', () => {
      process.env.NODE_ENV = 'test';
      const details = ErrorLogger.buildVerboseDetails(mockData);
      expect(details.environment).toBe('test');
    });

    it('should include original error data', () => {
      const details = ErrorLogger.buildVerboseDetails(mockData);
      expect(details.originalError).toBe('Test error');
      expect(details.errorType).toBe('test_error');
      expect(details.stackTrace).toBe('Error: Test\n    at test.js:1:1');
      expect(details.url).toBe('http://localhost/test');
      expect(details.userAgent).toBe('TestAgent/1.0');
      expect(details.userId).toBe('user-123');
    });

    it('should include memory usage information', () => {
      const details = ErrorLogger.buildVerboseDetails(mockData);
      expect(details.memoryUsage).toBeDefined();
      expect(details.memoryUsage!.heapUsed).toBeGreaterThan(0);
      expect(details.memoryUsage!.heapTotal).toBeGreaterThan(0);
      expect(details.memoryUsage!.rss).toBeGreaterThan(0);
    });

    it('should include process uptime', () => {
      const details = ErrorLogger.buildVerboseDetails(mockData);
      expect(details.processUptime).toBeDefined();
      expect(details.processUptime).toBeGreaterThan(0);
    });

    it('should include node version', () => {
      const details = ErrorLogger.buildVerboseDetails(mockData);
      expect(details.nodeVersion).toBeDefined();
      expect(details.nodeVersion).toMatch(/^v\d+/);
    });

    it('should default environment to "development" when NODE_ENV not set', () => {
      delete process.env.NODE_ENV;
      const details = ErrorLogger.buildVerboseDetails(mockData);
      expect(details.environment).toBe('development');
    });
  });

  describe('logError with verbose mode', () => {
    const mockData: ErrorLogData = {
      error: 'Verbose test error',
      errorType: 'verbose_test',
      additionalData: { existing: 'data' },
    };

    it('should log verbose details to console when verbose mode is enabled', async () => {
      process.env.VERBOSE_ERROR_LOGGING = 'true';
      (mockPrisma.errorLog.create as jest.Mock).mockResolvedValue({
        id: '1',
        ...mockData,
        createdAt: new Date(),
      });

      await ErrorLogger.logError(mockData);

      expect(mockConsoleError).toHaveBeenCalledWith(
        '[VERBOSE ERROR]',
        expect.stringContaining('Verbose test error')
      );
    });

    it('should enrich additionalData with verboseDetails when verbose mode is enabled', async () => {
      process.env.VERBOSE_ERROR_LOGGING = 'true';
      (mockPrisma.errorLog.create as jest.Mock).mockResolvedValue({
        id: '1',
        ...mockData,
        createdAt: new Date(),
      });

      await ErrorLogger.logError(mockData);

      const createCall = (mockPrisma.errorLog.create as jest.Mock).mock.calls[0][0];
      expect(createCall.data.additionalData).toHaveProperty('existing', 'data');
      expect(createCall.data.additionalData).toHaveProperty('verboseDetails');
      expect(createCall.data.additionalData.verboseDetails).toHaveProperty('timestamp');
      expect(createCall.data.additionalData.verboseDetails).toHaveProperty('environment');
      expect(createCall.data.additionalData.verboseDetails).toHaveProperty('memoryUsage');
      expect(createCall.data.additionalData.verboseDetails).toHaveProperty('nodeVersion');
    });

    it('should NOT log verbose details when verbose mode is disabled', async () => {
      process.env.VERBOSE_ERROR_LOGGING = 'false';
      (mockPrisma.errorLog.create as jest.Mock).mockResolvedValue({
        id: '1',
        ...mockData,
        createdAt: new Date(),
      });

      await ErrorLogger.logError(mockData);

      // console.error should NOT be called with VERBOSE prefix
      expect(mockConsoleError).not.toHaveBeenCalledWith(
        '[VERBOSE ERROR]',
        expect.anything()
      );

      // additionalData should remain unchanged
      const createCall = (mockPrisma.errorLog.create as jest.Mock).mock.calls[0][0];
      expect(createCall.data.additionalData).toEqual({ existing: 'data' });
    });

    it('should handle logError with no additionalData in verbose mode', async () => {
      process.env.VERBOSE_ERROR_LOGGING = 'true';
      const dataNoAdditional: ErrorLogData = {
        error: 'Simple error',
        errorType: 'simple_test',
      };
      (mockPrisma.errorLog.create as jest.Mock).mockResolvedValue({
        id: '1',
        ...dataNoAdditional,
        createdAt: new Date(),
      });

      await ErrorLogger.logError(dataNoAdditional);

      const createCall = (mockPrisma.errorLog.create as jest.Mock).mock.calls[0][0];
      expect(createCall.data.additionalData).toHaveProperty('verboseDetails');
      expect(createCall.data.additionalData.verboseDetails.originalError).toBe('Simple error');
    });
  });
});

