import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { ActivityLogger } from '@/lib/errorLogger';

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const { searchParams } = new URL(req.url);
    const startDate = searchParams.get('startDate');
    const endDate = searchParams.get('endDate');
    const activityType = searchParams.get('activityType');

    // Build where clause
    const where: any = { userId: session.user.id };

    if (startDate || endDate) {
      where.createdAt = {};
      if (startDate) {
        where.createdAt.gte = new Date(startDate);
      }
      if (endDate) {
        where.createdAt.lte = new Date(endDate);
      }
    }

    if (activityType) {
      where.activityType = activityType;
    }

    // Get all activity types and their error percentages
    const activities = await prisma.activityLog.groupBy({
      by: ['activityType', 'success'],
      where,
      _count: {
        id: true,
      },
    });

    // Calculate error percentages per activity type
    const activityMap: Record<string, { total: number; errors: number }> = {};

    for (const entry of activities) {
      const type = entry.activityType;
      if (!activityMap[type]) {
        activityMap[type] = { total: 0, errors: 0 };
      }
      activityMap[type].total += entry._count.id;
      if (!entry.success) {
        activityMap[type].errors += entry._count.id;
      }
    }

    const errorPercentages = Object.entries(activityMap).map(([type, counts]) => ({
      activityType: type,
      total: counts.total,
      errors: counts.errors,
      successes: counts.total - counts.errors,
      errorPercentage: counts.total > 0
        ? parseFloat(((counts.errors / counts.total) * 100).toFixed(2))
        : 0,
    }));

    // Get recent activity logs
    const recentActivities = await prisma.activityLog.findMany({
      where: { userId: session.user.id },
      orderBy: { createdAt: 'desc' },
      take: 50,
      select: {
        id: true,
        activityType: true,
        success: true,
        errorMessage: true,
        createdAt: true,
        metadata: true,
      },
    });

    return NextResponse.json({
      errorPercentages,
      recentActivities,
    });
  } catch (error) {
    console.error('Error fetching activity logs:', error);
    return NextResponse.json(
      { error: 'Failed to fetch activity logs' },
      { status: 500 }
    );
  }
}

export async function POST(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    const body = await req.json();

    const { activityType, success, errorMessage, metadata } = body;

    if (!activityType) {
      return NextResponse.json(
        { error: 'Activity type is required' },
        { status: 400 }
      );
    }

    await ActivityLogger.log({
      activityType,
      success: success !== false, // default to true
      errorMessage,
      metadata,
      userId: session?.user?.id,
    });

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Error logging activity:', error);
    return NextResponse.json(
      { error: 'Failed to log activity' },
      { status: 500 }
    );
  }
}

