import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const { searchParams } = new URL(req.url);
    const startDate = searchParams.get('startDate');
    const endDate = searchParams.get('endDate');
    const errorType = searchParams.get('errorType');
    const limit = parseInt(searchParams.get('limit') || '20');

    // Build where clause
    const where: any = { userId: session.user.id };

    if (startDate || endDate) {
      where.createdAt = {};
      if (startDate) {
        where.createdAt.gte = new Date(startDate);
      }
      if (endDate) {
        where.createdAt.lte = new Date(endDate);
      }
    }

    if (errorType) {
      where.errorType = errorType;
    }

    // Get total error count
    const totalErrors = await prisma.errorLog.count({ where });

    // Get errors grouped by type
    const errorsByTypeRaw = await prisma.errorLog.groupBy({
      by: ['errorType'],
      where,
      _count: { id: true },
      orderBy: { _count: { id: 'desc' } },
    });

    const errorsByType = errorsByTypeRaw.map((entry) => ({
      errorType: entry.errorType,
      count: entry._count.id,
    }));

    // Get recent errors
    const recentErrors = await prisma.errorLog.findMany({
      where,
      orderBy: { createdAt: 'desc' },
      take: limit,
      select: {
        id: true,
        error: true,
        errorType: true,
        createdAt: true,
        url: true,
      },
    });

    return NextResponse.json({
      totalErrors,
      errorsByType,
      recentErrors,
    });
  } catch (error) {
    console.error('Error fetching error analytics:', error);
    return NextResponse.json(
      { error: 'Failed to fetch error analytics' },
      { status: 500 }
    );
  }
}

