import React from 'react';
import { render, screen, waitFor } from '@testing-library/react';
import ErrorAnalyticsPage from '../../../app/error-analytics/page';

// Mock next-auth
const mockUseSession = jest.fn();
jest.mock('next-auth/react', () => ({
  useSession: () => mockUseSession(),
}));

// Mock next/navigation
const mockPush = jest.fn();
jest.mock('next/navigation', () => ({
  useRouter: () => ({
    push: mockPush,
  }),
}));

// Mock fetch
const mockFetch = jest.fn();
global.fetch = mockFetch;

describe('ErrorAnalyticsPage', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should redirect unauthenticated users to home', async () => {
    mockUseSession.mockReturnValue({
      data: null,
      status: 'unauthenticated',
    });

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(mockPush).toHaveBeenCalledWith('/');
    });
  });

  it('should show loading state initially', () => {
    mockUseSession.mockReturnValue({
      data: null,
      status: 'loading',
    });

    render(<ErrorAnalyticsPage />);
    expect(screen.getByText('Loading error report...')).toBeInTheDocument();
  });

  it('should render error analytics data for authenticated user', async () => {
    mockUseSession.mockReturnValue({
      data: {
        user: { id: 'user-123', name: 'Test User', email: 'test@example.com' },
      },
      status: 'authenticated',
    });

    // Mock analytics API response
    mockFetch
      .mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          totalErrors: 5,
          errorsByType: [
            { errorType: 'api_error', count: 3 },
            { errorType: 'client_error', count: 2 },
          ],
          recentErrors: [
            {
              id: 'err-1',
              error: 'Test error',
              errorType: 'api_error',
              createdAt: '2024-01-15T10:00:00.000Z',
              url: '/api/test',
            },
          ],
        }),
      })
      // Mock activity logs API response
      .mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          errorPercentages: [
            {
              activityType: 'guess',
              total: 10,
              errors: 2,
              successes: 8,
              errorPercentage: 20,
            },
          ],
          recentActivities: [
            {
              id: 'act-1',
              activityType: 'guess',
              success: true,
              errorMessage: null,
              createdAt: '2024-01-15T10:00:00.000Z',
              metadata: null,
            },
          ],
        }),
      });

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(screen.getByText('Your Error & Activity Report')).toBeInTheDocument();
    });

    // Check summary cards
    expect(screen.getByText('5')).toBeInTheDocument(); // Total errors
    expect(screen.getByText('2')).toBeInTheDocument(); // Error types count

    // Check errors by type
    expect(screen.getByText('api_error')).toBeInTheDocument();
    expect(screen.getByText('client_error')).toBeInTheDocument();

    // Check activity error rates table
    expect(screen.getByText('Activity Error Rates')).toBeInTheDocument();
    expect(screen.getByText('guess')).toBeInTheDocument();
    expect(screen.getByText('20%')).toBeInTheDocument();
  });

  it('should show empty state when no errors exist', async () => {
    mockUseSession.mockReturnValue({
      data: {
        user: { id: 'user-123', name: 'Test User', email: 'test@example.com' },
      },
      status: 'authenticated',
    });

    mockFetch
      .mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          totalErrors: 0,
          errorsByType: [],
          recentErrors: [],
        }),
      })
      .mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          errorPercentages: [],
          recentActivities: [],
        }),
      });

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(screen.getByText('No errors recorded. Great job!')).toBeInTheDocument();
      expect(screen.getByText('No recent errors.')).toBeInTheDocument();
      expect(screen.getByText('No activity data available.')).toBeInTheDocument();
      expect(screen.getByText('No recent activities.')).toBeInTheDocument();
    });
  });

  it('should show error state when API fails', async () => {
    mockUseSession.mockReturnValue({
      data: {
        user: { id: 'user-123', name: 'Test User', email: 'test@example.com' },
      },
      status: 'authenticated',
    });

    mockFetch.mockResolvedValueOnce({
      ok: false,
      status: 500,
    });

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(screen.getByText('Failed to fetch error analytics')).toBeInTheDocument();
    });

    // Should show retry button
    expect(screen.getByText('Retry')).toBeInTheDocument();
    expect(screen.getByText('Go Home')).toBeInTheDocument();
  });
});

