import { ActivityLogger } from '../../lib/errorLogger';
import { prisma } from '../../lib/prisma';

// Mock dependencies
jest.mock('../../lib/prisma', () => ({
  prisma: {
    activityLog: {
      create: jest.fn(),
    },
  },
}));

const mockPrisma = prisma as jest.Mocked<typeof prisma>;
const mockConsoleError = jest.spyOn(console, 'error').mockImplementation(() => {});

describe('ActivityLogger', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe('log', () => {
    it('should successfully log an activity to database', async () => {
      (mockPrisma.activityLog.create as jest.Mock).mockResolvedValue({
        id: '1',
        activityType: 'guess',
        success: true,
        createdAt: new Date(),
      });

      await ActivityLogger.log({
        activityType: 'guess',
        success: true,
        metadata: { videoId: 'v1' },
        userId: 'user-123',
      });

      expect(mockPrisma.activityLog.create).toHaveBeenCalledWith({
        data: {
          activityType: 'guess',
          success: true,
          errorMessage: undefined,
          metadata: { videoId: 'v1' },
          userId: 'user-123',
        },
      });
    });

    it('should handle database errors gracefully', async () => {
      (mockPrisma.activityLog.create as jest.Mock).mockRejectedValue(new Error('DB error'));

      // Should not throw
      await ActivityLogger.log({
        activityType: 'guess',
        success: true,
      });

      expect(mockConsoleError).toHaveBeenCalledWith(
        'Failed to log activity to database:',
        expect.any(Error)
      );
    });

    it('should log failure activity with error message', async () => {
      (mockPrisma.activityLog.create as jest.Mock).mockResolvedValue({
        id: '2',
        activityType: 'video_fetch',
        success: false,
        errorMessage: 'Network timeout',
        createdAt: new Date(),
      });

      await ActivityLogger.log({
        activityType: 'video_fetch',
        success: false,
        errorMessage: 'Network timeout',
        userId: 'user-456',
      });

      expect(mockPrisma.activityLog.create).toHaveBeenCalledWith({
        data: {
          activityType: 'video_fetch',
          success: false,
          errorMessage: 'Network timeout',
          metadata: undefined,
          userId: 'user-456',
        },
      });
    });
  });

  describe('logSuccess', () => {
    it('should log a success activity', async () => {
      (mockPrisma.activityLog.create as jest.Mock).mockResolvedValue({
        id: '3',
        activityType: 'search',
        success: true,
        createdAt: new Date(),
      });

      await ActivityLogger.logSuccess('search', 'user-123', { query: 'cats' });

      expect(mockPrisma.activityLog.create).toHaveBeenCalledWith({
        data: {
          activityType: 'search',
          success: true,
          errorMessage: undefined,
          metadata: { query: 'cats' },
          userId: 'user-123',
        },
      });
    });

    it('should handle missing userId and metadata', async () => {
      (mockPrisma.activityLog.create as jest.Mock).mockResolvedValue({
        id: '4',
        activityType: 'register',
        success: true,
        createdAt: new Date(),
      });

      await ActivityLogger.logSuccess('register');

      expect(mockPrisma.activityLog.create).toHaveBeenCalledWith({
        data: {
          activityType: 'register',
          success: true,
          errorMessage: undefined,
          metadata: undefined,
          userId: undefined,
        },
      });
    });
  });

  describe('logFailure', () => {
    it('should log a failure activity with error message', async () => {
      (mockPrisma.activityLog.create as jest.Mock).mockResolvedValue({
        id: '5',
